import React, { useState } from "react";
import { Bar, Line, Pie } from "react-chartjs-2";
import "./Charts.css";

import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  ArcElement,
  PointElement,   // ✅ VERY IMPORTANT
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  ArcElement,
  PointElement,   // ✅ FIXES YOUR ERROR
  Tooltip,
  Legend
);
const Charts = () => {
  const [activeChart, setActiveChart] = useState("bar");

  const salaryByRole = {
    labels: ["Developer", "Data Scientist", "Tester"],
    datasets: [
      {
        label: "Salary",
        data: [40000, 60000, 30000],
      },
    ],
  };

  const experienceData = {
    labels: [1, 2, 3, 4, 5],
    datasets: [
      {
        label: "Salary Growth",
        data: [20000, 30000, 45000, 60000, 80000],
      },
    ],
  };

  const skillsData = {
    labels: ["Python", "Java", "ML", "Others"],
    datasets: [
      {
        data: [30, 25, 25, 20],
      },
    ],
  };

  return (
    <div className="charts-container">
      
      <h2 className="charts-title">📊 Analytics Dashboard</h2>

      {/* 🔥 Tab Buttons */}
      <div className="chart-tabs">
        <button 
          className={activeChart === "bar" ? "active" : ""}
          onClick={() => setActiveChart("bar")}
        >
          Salary
        </button>

        <button 
          className={activeChart === "line" ? "active" : ""}
          onClick={() => setActiveChart("line")}
        >
          Experience
        </button>

        <button 
          className={activeChart === "pie" ? "active" : ""}
          onClick={() => setActiveChart("pie")}
        >
          Skills
        </button>
      </div>

     <div className="chart-box">
  {activeChart === "bar" && <Bar key="bar" data={salaryByRole} />}
  {activeChart === "line" && <Line key="line" data={experienceData} />}
  {activeChart === "pie" && <Pie key="pie" data={skillsData} />}
</div>

    </div>
  );
};

export default Charts;
